Rule.Source:
import sailpoint.object.Field;
  import sailpoint.object.Form;
  import sailpoint.object.Identity;
  import sailpoint.tools.Util;

  if (identity != null) {

    email = identity.getEmail();

    if (Util.isNotNullOrEmpty(email)) {

      field.setReadOnly(true);
      return email;

    } else if (Util.isNullOrEmpty(email)) {

      field.setReadOnly(true);

      if (Util.isNotNullOrEmpty(prefixField) && Util.isNotNullOrEmpty(suffixField)) {

        dynamicEmail = queryUntilUnique(prefixField, suffixField);

        if (Util.isNotNullOrEmpty(dynamicEmail)) {

          return dynamicEmail;

        } else {

          field.setReadOnly(false);
          return null;

        }

      } else {

        field.setReadOnly(false);
        return null;

      }

    } else {

      field.setReadOnly(false);
      return null;

    }

  } else {

    field.setReadOnly(false);
    return null;

  }
